    status?: 'pending' | 'completed' | 'overdue';
    priority?: 'low' | 'medium' | 'high';
    tags?: string;
    due_date_from?: string;
    due_date_to?: string;
    sort_by?: 'due_date' | 'priority' | 'created_at' | 'title';
    order?: 'asc' | 'desc';
    offset?: number;
    limit?: number;
